const arrayData = {{workflowparams:arrayData}};
const allData = arrayData[0];
const unique = `${allData.created_by || ""}_${Date.now()}`;

return {
  unique
};

const arrayData = {{workflowparams:arrayData}}
const currentIndexRaw = {{node:get_cache_node_hGFbHnzQ.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0
const saveAs = {{workflowparams:saveAs}}
const pageStatus = {{workflowparams:pageStatus}}

let data = arrayData[index];
let invalidMessage = "";

// Validation: For saveAs "Completed", at least one item must have picked_qty > 0
if (saveAs === "Completed") {
  const hasPickedQty = data.table_picking_items && data.table_picking_items.length > 0 &&
    data.table_picking_items.some(item => item.picked_qty > 0);

  if (!hasPickedQty) {
    invalidMessage = "Cannot complete picking. At least one item must have picked quantity greater than 0.";
  }
}

if (saveAs !== "Cancelled") {
  if (saveAs === "Draft") {
    if (
      data.to_id_type !== -9999 &&
      (!data.to_id ||
        data.to_id === null ||
        data.to_id === "")
    ) {
      data.to_id = "draft";
    }
  } else {
    if (
      data.to_id_type !== -9999 &&
      (!data.to_id ||
        data.to_id === null ||
        data.to_id === "" ||
        data.to_status === "Draft")
    ) {
      data.to_id = "issued";
    }
  }
}

let updatedStatus = {{workflowparams:saveAs}}
if (saveAs === "Completed" && pageStatus === "Add") {
  updatedStatus = "Created"
}

return {
  data,
  updatedStatus,
  nextIndex: index + 1,
  invalidMessage,
  isInvalid: invalidMessage === "" ? 0 : 1
}

return {
  required_fields: JSON.stringify([
      { name: "plant_id", label: "Plant" },
      { name: "to_id", label: "Transfer Order No" },
      { name: "ref_doc_type", label: "Reference Document Type" },
      {
        name: "table_picking_items",
        label: "Picking Items",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
      },
]),
  data: JSON.stringify({
    plant_id: {{node:code_node_hjAwTKzF.data.data.plant_id}},
    to_id: {{node:code_node_hjAwTKzF.data.data.to_id}},
    ref_doc_type: {{node:code_node_hjAwTKzF.data.data.ref_doc_type}},
    table_picking_items: {{node:code_node_hjAwTKzF.data.data.table_picking_items}},
  })
}

let data = {{node:code_node_hjAwTKzF.data.data}} || {}

// Helper function to format qty and price fields to 3 decimal places
const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};
// Format qty fields in table_picking_items
if (data.table_picking_items && data.table_picking_items.length > 0) {
  data.table_picking_items = data.table_picking_items.map(item => ({
    ...item,
    qty_to_pick: formatNumber(item.qty_to_pick),
    pending_process_qty: formatNumber(item.pending_process_qty),
    picked_qty: formatNumber(item.picked_qty),
  }));
}
// Format qty fields in table_picking_records if exists
if (data.table_picking_records && data.table_picking_records.length > 0) {
  data.table_picking_records = data.table_picking_records.map(item => ({
    ...item,
    qty_to_pick: formatNumber(item.qty_to_pick),
    picked_qty: formatNumber(item.picked_qty),
    store_out_qty: formatNumber(item.store_out_qty),
  }));
}

return {
  data
}

const pageStatus = {{workflowparams:pageStatus}}

let pickingData = {{node:code_node_hjAwTKzF.data.data}}

if (pageStatus === 'Add') {
  const rawData = {{node:add_node_j6HU6pFP.data}}
  pickingData = rawData[0]
  pickingData.table_picking_items = {{node:search_node_OmBi3hyy.data.data}}
}

return {
  pickingData
}

const pageStatus = {{workflowparams:pageStatus}}

let pickingData = {{node:code_node_hjAwTKzF.data.data}}

if (pageStatus === 'Add') {
  const rawData = {{node:add_node_j6HU6pFP.data}}
  pickingData = rawData[0]
  pickingData.table_picking_items = {{node:search_node_OmBi3hyy.data.data}}
} else {
  pickingData = {{node:get_node_xPyPMAKx.data.data}}
}

const isPickingPlan = pickingData.ref_doc_type === "Picking Plan" ? 1 : 0;

const gdIds = pickingData.table_picking_items.filter((item) => item.line_status !== "Cancelled").map((item) => item.gd_id);

const toIds = pickingData.table_picking_items.filter((item) => item.line_status !== "Cancelled").map((item) => item.to_id);

const filteredPickingItems = pickingData.table_picking_items.filter((item) => item.line_status !== "Cancelled",);

return {
  gdIds,
  toIds,
  filteredPickingItems,
  isPickingPlan,
}
